code.C:
#include <stdio.h>
int digitalRoot(int n) {
    if (n < 10) return n;
    return digitalRoot(n / 10 + n % 10);
}
int main() {
    int n;
    scanf("%d", &n);
    printf("%d\n", digitalRoot(n));
    return 0;
}

